SourceCode.Declaration:
/// <summary>
/// Handles datasource write events (insert, update, delete) and logs them
/// to the DEVLicenseTablesUsers table with deduplication support.
/// </summary>
public class DEVLicenseWriteMonitor
{
    public static Set usedWriteSet;

}

Method.Source:
/// <summary>
/// Called after a record is inserted through a form datasource.
/// </summary>
public static void onDsInserted(FormDataSource _fds, FormDataSourceEventArgs _e)
{
    DEVLicenseWriteMonitor::logWrite(_fds, 'RealTimeInsert');
}

/// <summary>
/// Called after a record is updated through a form datasource.
/// </summary>
public static void onDsUpdated(FormDataSource _fds, FormDataSourceEventArgs _e)
{
    DEVLicenseWriteMonitor::logWrite(_fds, 'RealTimeUpdate');
}

/// <summary>
/// Called after a record is deleted through a form datasource.
/// </summary>
public static void onDsDeleted(FormDataSource _fds, FormDataSourceEventArgs _e)
{
    DEVLicenseWriteMonitor::logWrite(_fds, 'RealTimeDelete');
}

/// <summary>
/// Logs a write operation to the DEVLicenseTablesUsers table.
/// In Summary mode, only one entry per user/table/source is logged per session.
/// In Full mode, every write operation is logged.
/// </summary>
public static void logWrite(FormDataSource _fds, str _source)
{
    try
    {
        DEVLicenseCaptureElementUsageType  captureType = SysIntParameters::Find().DEVLicenseCaptureWriteLog;
        if (captureType == DEVLicenseCaptureElementUsageType::None)
        {
            return;
        }

        FormRun formRun = _fds.formRun();
        if (!formRun || !formRun.args() || !formRun.args().menuItemName())
        {
            return;
        }

        str tableName    = tableId2Name(_fds.table());

        DEVLicenseTablesUsers tablesUsers;
        tablesUsers.UserId        = curUserId();
        tablesUsers.TableName     = tableName;
        tablesUsers.Source        = _source;
        tablesUsers.AOTName       = formRun.args().menuItemName();
        tablesUsers.SecurableType = DEVLicenseElementUsageLogMonitor::menuItemTypeToSecurable(formRun.args().menuItemType());

        if (captureType == DEVLicenseCaptureElementUsageType::Summary)
        {
            str usageKey = strFmt('%1|%2|%3|%4',
                                    tablesUsers.UserId,
                                    tablesUsers.TableName,
                                    tablesUsers.Source,
                                    tablesUsers.AOTName);

            if (!DEVLicenseWriteMonitor::usedWriteSet)
            {
                DEVLicenseWriteMonitor::usedWriteSet = new Set(Types::String);
            }
            Set localVarSet = DEVLicenseWriteMonitor::usedWriteSet;

            if (!localVarSet.in(usageKey))
            {
                localVarSet.add(usageKey);
                tablesUsers.insert();
            }
        }
        else if (captureType == DEVLicenseCaptureElementUsageType::Full)
        {
            tablesUsers.insert();
        }
    }
    catch
    {
    }
}
